import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.stub.StreamObserver;

import java.io.FileOutputStream;
import java.io.IOException;
import java.io.InputStream;

public class DataProcessingService extends DataProcessingServiceGrpc.DataProcessingServiceImplBase {

    @Override
    public StreamObserver<UploadFileRequest> uploadFile(StreamObserver<UploadFileResponse> responseObserver) {
        return new StreamObserver<UploadFileRequest>() {
            FileOutputStream output = null;

            @Override
            public void onNext(UploadFileRequest request) {
                try {
                    if (output == null) {
                        output = new FileOutputStream(request.getFileName());
                    }
                    output.write(request.getData().toByteArray());
                    output.flush();
                } catch (IOException e) {
                    e.printStackTrace();
                }
            }

            @Override
            public void onError(Throwable t) {
                if (output != null) {
                    try {
                        output.close();
                    } catch (IOException e) {
                        e.printStackTrace();
                    }
                }
            }

            @Override
            public void onCompleted() {
                try {
                    output.close();
                    responseObserver.onNext(UploadFileResponse.newBuilder().setMessage("File uploaded successfully").build());
                    responseObserver.onCompleted();
                } catch (IOException e) {
                    e.printStackTrace();
                }
            }
        };
    }

    public static void main(String[] args) throws IOException, InterruptedException {
        Server server = ServerBuilder.forPort(9090)
                .addService(new DataProcessingService())
                .build();

        server.start();
        System.out.println("Server started on port 9090");

        server.awaitTermination();
    }
}